# Module providing geometric shape classes and interfaces

interface IDrawable:
    def draw() -> str: ...

class Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

    def __str__(self) -> str:
        return f"({self.x}, {self.y})"

class Shape(IDrawable):
    position: Point

    def __init__(self, x: float, y: float):
        self.position = Point(x, y)

    @virtual
    def area(self) -> float:
        return 0.0

    @override
    def draw(self) -> str:
        return f"Shape at {self.position}"

class Circle(Shape):
    radius: float

    def __init__(self, x: float, y: float, radius: float):
        super().__init__(x, y)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def draw(self) -> str:
        return f"Circle at {self.position} with radius {self.radius}"

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, x: float, y: float, width: float, height: float):
        super().__init__(x, y)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def draw(self) -> str:
        return f"Rectangle at {self.position}, size {self.width}x{self.height}"

