# Utility module for shape operations

from shapes import Shape, Circle, Rectangle

def calculate_total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for shape in shapes:
        total += shape.area()
    return total

def describe_shape(shape: Shape) -> str:
    description: str = shape.draw()
    area: float = shape.area()
    return f"{description} [Area: {area}]"

def create_circle_at_origin(radius: float) -> Circle:
    return Circle(0.0, 0.0, radius)
